@Override
    @Transactional(rollbackFor = Exception.class)
    public Integer submitStageOne(DRCStageOneInputVo drcStageOneInputVo) {
        //验证
        validStageOne(drcStageOneInputVo);
        //判断是否更换DBO
        boolean updateDBOOrNewDbo = isUpdateDBOOrNewDbo(drcStageOneInputVo.getId(), drcStageOneInputVo.getTopWheelId());
        //保存stage
        saveStageOne(drcStageOneInputVo);
        //更新stage
        dataResCatalogBaseService.updateDRCStage(DRCStageEnum.TWO,drcStageOneInputVo.getId());
        //stage two 默认值插入
        saveDefaultStageTwo(drcStageOneInputVo.getId(),drcStageOneInputVo.getTopWheelId(),updateDBOOrNewDbo);

        releaseReeditModifyStatusAndStage(drcStageOneInputVo.getId());
        return drcStageOneInputVo.getId();
    }
