@Override
public void startApproval(List<ApprovalStageDetailVo> stages, Integer channelId) {
    final int expectedStage = DRCStageEnum.FIVE.getCode();
    final int expectedStatus = DRCStatusEnum.DRAFT.getCode();

    // 获取基本信息
    DataResourceCatalogBaseInfo baseInfo = dataResCatalogBaseService.getBaseInfoThrowE(channelId);
    validateStageAndStatus(baseInfo, expectedStage, expectedStatus);

    // 准备上下文信息
    JSONObject context = prepareContext(channelId, baseInfo);

    // 提交基本信息
    dataResCatalogBaseService.baseSubmit(baseInfo);

    try {
        ApprovalVo approvalVo = getApprovalVo(channelId, baseInfo.getTopWheelId());
        approvalHelper.handleApprovalNodeByUserChoose(stages, approvalVo);

        approvalVo.setContext(JSONUtil.toJsonStr(context));
        approvalBaseService.addApproval2Db(approvalVo);

        handleApprovalStatus(approvalVo, channelId, baseInfo);
    } catch (Exception e) {
        logApprovalError(channelId, e);
        throw new RuntimeException(e);
    }
}

private void validateStageAndStatus(DataResourceCatalogBaseInfo baseInfo, int expectedStage, int expectedStatus) {
    if (!ObjectUtil.equals(baseInfo.getStage(), expectedStage)
            || !ObjectUtil.equals(baseInfo.getStatus(), expectedStatus)) {
        throw new BusinessException(ErrorEnum.PARAM_ERROR, "this data can't be submitted");
    }
}

private JSONObject prepareContext(Integer channelId, DataResourceCatalogBaseInfo baseInfo) {
    JSONObject context = new JSONObject();
    context.set("moduleDetail", DataWheelConstant.BUSINESS_OBJECT_ID_MAP_INVERT.get(baseInfo.getTopWheelId()) + " " + ApprovalChannelConstant.DATA_RESOURCE_CATALOG)
            .set("dataResourceCatalogBaseInfoId", channelId);
    return context;
}

private void handleApprovalStatus(ApprovalVo approvalVo, Integer channelId, DataResourceCatalogBaseInfo baseInfo) {
    if (ApprovalStatusEnum.APPROVED.getCode().equals(approvalVo.getStatus())) {
        // 被注释的代码可能包含与业务逻辑相关的重要操作，确保在真正需要时启用并测试
        // 这里仅提供相应的调用结构，具体实现可能需要根据实际业务情况调整
        updateDRCStageAndStatus(channelId, baseInfo);
        executeDRCMergeExecutor(channelId);
    }
}

private void updateDRCStageAndStatus(Integer channelId, DataResourceCatalogBaseInfo baseInfo) {
    // Implementation details can vary based on your actual requirements
    // Ensure to test this method when enabling it
}

private void executeDRCMergeExecutor(Integer channelId) {
    // Implementation details can vary based on your actual requirements
    // Ensure to test this method when enabling it
}

private void logApprovalError(Integer channelId, Exception e) {
    log.error("data resource catalog approval start error, id:{}, error info: ", channelId, e);
}
