// 使用Optional来处理可能的空值，增强代码的健壮性
Optional<DataResourceCatalogInstanceBizObj> detailOpt = dataResCatalogBaseService.getInstanceExternalDetail(instanceVo.getId(), DRCDefinitionConstant.BIZ_OBJ)
        .map(dataResCatalogBaseService::convertToBizObj);

detailOpt.ifPresent(detail -> {
    // 初始化bizObject并设置基本属性
    DRCInstanceVo.BizObject bizObject = new DRCInstanceVo.BizObject();
    bizObject.setBizObjName(vo.getBizObjName());
    bizObject.setDescription(vo.getDescription());
    bizObject.setMasterDataFlag(FlagStringEnum.NO.getCode());
    bizObject.setItProduct(vo.getItProduct());
    BeanUtil.copyProperties(vo, bizObject, "id");

    // 设置ID并关联至instanceVo
    bizObject.setId(detail.getId());
    instanceVo.setBizObject(bizObject);

    // 保存或更新实例
    Integer instanceId = saveOrUpdateInstance(instanceVo, Constant.DB_BOOLEAN_FLAG_Y, true);

    // 检查并更新阶段状态
    checkAndUpdateStage(instanceId, bizObjManualInfo);
});

// 分离出检查并更新阶段状态的逻辑
private void checkAndUpdateStage(Integer instanceId, DataResourceCatalogBizObjManualInfo bizObjManualInfo) {
    if (StrUtil.equals(bizObjManualInfo.getMaxStage(), DRCBizObjStageEnum.ZERO.getCode())) {
        DataResourceCatalogBizObjManualInfo manualInfo = new DataResourceCatalogBizObjManualInfo();
        manualInfo.setInstanceId(instanceId);
        manualInfo.setStatus(DRCBizObjStatusEnum.DRAFT.getCode());
        manualInfo.setMaxStage(DRCBizObjStageEnum.ONE.getCode());

        dataResCatalogBaseService.updateBizObjManualInfoByInstanceId(manualInfo);
    }
}
```

